## 10. MESSAGE HANDLING PATTERNS

### Inbound (Receiving)

**Pattern (Nostr):**
```typescript
gateway: {
  startAccount: async (ctx) => {
    const bus = await startNostrBus({
      accountId: account.accountId,
      privateKey: account.privateKey,
      relays: account.relays,
      authorizeSender: async ({ senderPubkey, reply }) => {
        // Pre-check authorization before processing message
      },
      onMessage: async (senderPubkey, text, reply, meta) => {
        // 1. Resolve inbound access (allowlist, pairing, etc.)
        const resolvedAccess = await resolveNostrDirectAccess({
          cfg: ctx.cfg,
          accountId: account.accountId,
          dmPolicy: account.config.dmPolicy ?? "pairing",
          allowFrom: account.config.allowFrom,
          senderPubkey,
          rawBody: text,
          runtime: ctx.runtime,
        });

        if (resolvedAccess.access.decision !== "allow") {
          return; // Dropped
        }

        // 2. Dispatch to runtime (handles queuing, context, agent invocation)
        await dispatchInboundDirectDmWithRuntime({
          cfg: ctx.cfg,
          runtime,
          channel: "nostr",
          accountId: account.accountId,
          peer: { kind: "direct", id: senderPubkey },
          senderId: senderPubkey,
          senderAddress: `nostr:${senderPubkey}`,
          rawBody: text,
          messageId: meta.eventId,
          timestamp: meta.createdAt * 1000,
          commandAuthorized: resolvedAccess.commandAuthorized,
          // 3. Define delivery callback for outbound responses
          deliver: async (payload) => {
            const outboundText = (payload as { text?: string }).text ?? "";
            const tableMode = runtime.channel.text.resolveMarkdownTableMode({...});
            await reply(runtime.channel.text.convertMarkdownTables(outboundText, tableMode));
          },
        });
      },
      onError: (error, context) => {
        ctx.log?.error?.(`[${account.accountId}] Nostr error: ${error.message}`);
      },
    });
  },
}
```

### Outbound (Sending)

**Pattern (IRC):**
```typescript
export async function sendMessageIrc(
  to: string,
  text: string,
  opts: SendIrcOptions = {},
): Promise<SendIrcResult> {
  const runtime = getIrcRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolveIrcAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(`IRC is not configured for account "${account.accountId}"`);
  }

  const target = resolveTarget(to, opts);
  const tableMode = resolveMarkdownTableMode({ cfg, channel: "irc", accountId: account.accountId });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  // Send message via IRC client
  const messageId = await ircClient.send(target, payload);

  recordIrcOutboundActivity(account.accountId);

  return { messageId, target };
}
```

