  opts: SendIrcOptions = {},
): Promise<SendIrcResult> {
  const runtime = getIrcRuntime();
  const cfg = (opts.cfg ?? runtime.config.loadConfig()) as CoreConfig;
  const account = resolveIrcAccount({ cfg, accountId: opts.accountId });

  if (!account.configured) {
    throw new Error(`IRC is not configured for account "${account.accountId}"`);
  }

  const target = resolveTarget(to, opts);
  const tableMode = resolveMarkdownTableMode({ cfg, channel: "irc", accountId: account.accountId });
  const prepared = convertMarkdownTables(text.trim(), tableMode);
  const payload = opts.replyTo ? `${prepared}\n\n[reply:${opts.replyTo}]` : prepared;

  // Send message via IRC client
  const messageId = await ircClient.send(target, payload);

  recordIrcOutboundActivity(account.accountId);

  return { messageId, target };
}
