import type { DmPolicy, GroupPolicy, MarkdownConfig, OpenClawConfig } from "../runtime-api.js";

/** Per-board (group) configuration overrides. */
export type PulseBoardBoardConfig = {
  /** Require an @handle mention to trigger a reply in this board (default: true). */
  requireMention?: boolean;
  /** Whether this board is enabled for inbound messages (default: true). */
  enabled?: boolean;
  /** Allowlist of @handles or numeric user IDs allowed to trigger replies from this board. */
  allowFrom?: Array<string | number>;
  /** Optional per-board system prompt override. */
  systemPrompt?: string;
};

/** Top-level channels.pulseboard configuration block. */
export type PulseBoardAccountConfig = {
  /** Display name for this account. */
  name?: string;
  /** Whether the PulseBoard channel is enabled (default: true). */
  enabled?: boolean;
  /** PulseBoard server WebSocket URL, e.g., "wss://boards.example.com". */
  serverUrl?: string;
  /** API token for authenticating with the PulseBoard server (treated as a secret). */
  apiToken?: string;
  /** Your PulseBoard @handle used as the bot identity (e.g., "mybot"). */
  handle?: string;
  /** DM access policy: "pairing" | "allowlist" | "open" | "disabled". Default: "pairing". */
  dmPolicy?: DmPolicy;
  /** Allowlist of @handles or user IDs allowed to send DMs to this account. */
  allowFrom?: Array<string | number>;
  /** Board (group) access policy: "allowlist" | "open". Default: "allowlist". */
  groupPolicy?: GroupPolicy;
  /** Allowlist of @handles or user IDs allowed to trigger board replies. */
  groupAllowFrom?: Array<string | number>;
  /** Board names to subscribe to on connection (e.g., ["#tech", "#random"]). */
  boards?: string[];
  /** Per-board configuration keyed by board name (e.g., "#tech"). */
  boardConfigs?: Record<string, PulseBoardBoardConfig>;
  /** Markdown rendering/table options. */
  markdown?: MarkdownConfig;
  /** Maximum characters per outbound text chunk. Default: 4000. */
  textChunkLimit?: number;
};

/** OpenClaw config extended with the pulseboard channel section. */
export type CoreConfig = OpenClawConfig & {
  channels?: OpenClawConfig["channels"] & {
    pulseboard?: PulseBoardAccountConfig;
  };
};

/** A fully resolved PulseBoard account, ready for runtime use. */
export type ResolvedPulseBoardAccount = {
  accountId: string;
  name?: string;
  enabled: boolean;
  /** true when serverUrl, apiToken, and handle are all present. */
  configured: boolean;
  serverUrl: string;
  apiToken: string;
  handle: string;
  boards: string[];
  config: PulseBoardAccountConfig;
};

/** A decoded inbound message from the PulseBoard server. */
export type PulseBoardInboundMessage = {
  /** Unique message ID assigned by the PulseBoard server. */
  messageId: string;
  /**
   * For board messages: the board name (e.g., "#tech").
   * For DMs: the sender's @handle.
   */
  target: string;
  /** Sender @handle (e.g., "alice"). */
  senderHandle: string;
  /** Plain-text message body. */
  text: string;
  /** Message timestamp in milliseconds since Unix epoch. */
  timestamp: number;
  /** true if this message was posted to a board; false for direct messages. */
  isGroup: boolean;
};

