import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import { normalizeSecretInputString, type SecretInput } from "openclaw/plugin-sdk/secret-input";
import type { CoreConfig, PulseBoardAccountConfig, ResolvedPulseBoardAccount } from "./types.js";

// Normalized handle: strip leading "@" and lowercase.
function normalizeHandle(raw?: string): string {
  return (raw?.trim().replace(/^@/, "") ?? "").toLowerCase();
}

function resolveConfiguredDefaultPulseBoardAccountId(cfg: CoreConfig): string | undefined {
  const raw = cfg.channels?.pulseboard?.name?.trim();
  return raw ? normalizeAccountId(raw) : undefined;
}

/**
 * List all configured PulseBoard account IDs.
 * Currently only the single top-level account is supported.
 */
export function listPulseBoardAccountIds(cfg: CoreConfig): string[] {
  const pbCfg = cfg.channels?.pulseboard;
  const hasToken =
    Boolean(normalizeSecretInputString(pbCfg?.apiToken as SecretInput | undefined)) ||
    Boolean(process.env.PULSEBOARD_API_TOKEN?.trim());
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: hasToken
      ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

/** Return the default PulseBoard account ID for the given config. */
export function resolveDefaultPulseBoardAccountId(cfg: CoreConfig): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId: resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

/** Resolve a fully populated PulseBoard account from config. */
export function resolvePulseBoardAccount(params: {
  cfg: CoreConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    params.accountId ?? resolveDefaultPulseBoardAccountId(params.cfg),
  );
  const pbCfg: PulseBoardAccountConfig = params.cfg.channels?.pulseboard ?? {};

  const baseEnabled = pbCfg.enabled !== false;

  // Resolve serverUrl from config then env.
  const serverUrl = (
    pbCfg.serverUrl?.trim() ||
    (accountId === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_SERVER_URL?.trim() : "") ||
    ""
  ).trim();

  // Resolve apiToken from config then env (sensitive: use SecretInput normalization).
  const configToken = normalizeSecretInputString(pbCfg.apiToken as SecretInput | undefined) ?? "";
  const apiToken =
    configToken ||
    (accountId === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_API_TOKEN?.trim() ?? "" : "");

  // Resolve handle from config then env.
  const handle = normalizeHandle(
    pbCfg.handle ||
    (accountId === DEFAULT_ACCOUNT_ID ? process.env.PULSEBOARD_HANDLE : undefined),
  );

  const configured = Boolean(serverUrl && apiToken && handle);

  return {
    accountId,
    name: pbCfg.name?.trim() || undefined,
    enabled: baseEnabled,
    configured,
    serverUrl,
    apiToken,
    handle,
    boards: pbCfg.boards ?? [],
    config: pbCfg,
  };
}

/** Return all enabled PulseBoard accounts. */
export function listEnabledPulseBoardAccounts(cfg: CoreConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount({ cfg, accountId }))
    .filter((account) => account.enabled);
}

