/** Prefix used by PulseBoard board names. */
const BOARD_PREFIX = "#";

/**
 * Return true if the target string looks like a PulseBoard board name
 * (starts with "#").
 */
export function isBoardTarget(target: string): boolean {
  return target.trimStart().startsWith(BOARD_PREFIX);
}

/**
 * Normalize a PulseBoard messaging target.
 *
 * - Board names must start with "#" (e.g., "#tech"). Extra leading "#" chars
 *   are collapsed to one.
 * - User handles may start with "@" (e.g., "@alice") or be bare (e.g., "alice").
 *   The "@" is stripped and the result is lowercased.
 *
 * Returns null if the input is empty or cannot be normalized.
 */
export function normalizePulseBoardTarget(raw: string): string | null {
  const trimmed = raw.trim();
  if (!trimmed) {
    return null;
  }
  if (trimmed.startsWith(BOARD_PREFIX)) {
    // Collapse multiple leading "#" and lowercase.
    const name = trimmed.replace(/^#+/, BOARD_PREFIX).toLowerCase();
    // Board names must have at least one character after the "#".
    return name.length > 1 ? name : null;
  }
  // Strip optional leading "@" and lowercase for user handles.
  const handle = trimmed.replace(/^@/, "").toLowerCase();
  // Handles must be non-empty after normalization.
  return handle || null;
}

/**
 * Return true if the input looks like a PulseBoard target ID (board or handle).
 * Used by the messaging targetResolver.
 */
export function looksLikePulseBoardTargetId(input: string): boolean {
  return normalizePulseBoardTarget(input) !== null;
}

/**
 * Normalize a PulseBoard allowFrom entry.
 * Handles and board names are accepted; returns null for invalid entries.
 */
export function normalizePulseBoardAllowEntry(entry: string): string | null {
  if (entry.trim() === "*") {
    return "*";
  }
  return normalizePulseBoardTarget(entry);
}

