/**
 * Fictional PulseBoard WebSocket client.
 *
 * PulseBoard is an imaginary real-time bulletin board messaging platform.
 * Users post messages to named boards (e.g., #tech, #random) and can send
 * direct messages to one another by @handle.
 *
 * This module provides a minimal client interface that the gateway runtime
 * uses to connect to a PulseBoard server, subscribe to boards, receive
 * inbound messages, and deliver outbound replies.
 *
 * In a real implementation this module would open a WebSocket, authenticate
 * with the API token, and multiplex the board + DM event streams.  Here we
 * provide the typed surface and a stub implementation sufficient to make the
 * plugin structurally sound.
 */

import type { PulseBoardInboundMessage } from "./types.js";

export type PulseBoardClientOptions = {
  /** WebSocket URL of the PulseBoard server (e.g., "wss://boards.example.com"). */
  serverUrl: string;
  /** Bearer token for authentication. */
  apiToken: string;
  /** The bot's @handle on the server. */
  handle: string;
  /** Board names to subscribe to after connecting. */
  boards?: string[];
  /** Called when the connection is established. */
  onConnect?: () => void;
  /** Called when the connection is closed. */
  onDisconnect?: (reason: string) => void;
  /** Called for each inbound board post or direct message. */
  onMessage?: (message: PulseBoardInboundMessage) => void | Promise<void>;
  /** Called when an error occurs on the connection. */
  onError?: (error: Error) => void;
  /** AbortSignal to stop the client gracefully. */
  abortSignal?: AbortSignal;
};

export type PulseBoardClient = {
  /** Send a direct message to a @handle. */
  sendDirect(handle: string, text: string): Promise<void>;
  /** Post a message to a named board. */
  postToBoard(board: string, text: string): Promise<void>;
  /** Return true if the connection is currently active. */
  isConnected(): boolean;
  /** Cleanly disconnect from the server. */
  disconnect(): void;
};

/** Generate a pseudo-random message ID for outbound messages. */
export function makePulseBoardMessageId(): string {
  return `pb-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

/**
 * Connect to a PulseBoard server and return a client handle.
 *
 * This is a stub implementation.  A real implementation would:
 *   1. Open a WebSocket to `options.serverUrl`.
 *   2. Send an AUTH frame: `{ type: "auth", token: options.apiToken }`.
 *   3. After acknowledgement, send SUBSCRIBE frames for each board.
 *   4. Multiplex incoming JSON frames into `options.onMessage` callbacks.
 *   5. Reconnect with exponential back-off on unexpected disconnects.
 */
export async function connectPulseBoardClient(
  options: PulseBoardClientOptions,
): Promise<PulseBoardClient> {
  let connected = true;

  // Propagate abort as a clean disconnect.
  options.abortSignal?.addEventListener(
    "abort",
    () => {
      if (connected) {
        connected = false;
        options.onDisconnect?.("aborted");
      }
    },
    { once: true },
  );

  // Simulate a successful connection handshake.
  options.onConnect?.();

  return {
    async sendDirect(handle: string, text: string): Promise<void> {
      if (!connected) {
        throw new Error("PulseBoard client is not connected");
      }
      // Real implementation: send WS frame
      // { type: "dm", to: handle, body: text, requestId: makePulseBoardMessageId() }
      void handle;
      void text;
    },

    async postToBoard(board: string, text: string): Promise<void> {
      if (!connected) {
        throw new Error("PulseBoard client is not connected");
      }
      // Real implementation: send WS frame
      // { type: "post", board, body: text, requestId: makePulseBoardMessageId() }
      void board;
      void text;
    },

    isConnected(): boolean {
      return connected;
    },

    disconnect(): void {
      if (connected) {
        connected = false;
        options.onDisconnect?.("closed");
      }
    },
  };
}

