import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import type { OpenClawConfig } from "openclaw/plugin-sdk/config-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import { hasConfiguredSecretInput, normalizeSecretInputString } from "openclaw/plugin-sdk/secret-input";
import {
  createStandardChannelSetupStatus,
  createTopLevelChannelDmPolicy,
  createTopLevelChannelParsedAllowFromPrompt,
  formatDocsLink,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { resolvePulseBoardAccount } from "./accounts.js";
import { normalizePulseBoardAllowEntry } from "./normalize.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "Connect OpenClaw to a PulseBoard server for real-time board posts and direct messages.",
  "Required: server URL (wss://...), API token, and your @handle.",
  "Env vars supported: PULSEBOARD_SERVER_URL, PULSEBOARD_API_TOKEN, PULSEBOARD_HANDLE.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by @handle.",
  "Examples:",
  "- alice",
  "- @alice",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parsePulseBoardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const normalized = normalizePulseBoardAllowEntry(entry);
    if (!normalized) {
      return { error: `Invalid PulseBoard handle or wildcard: "${entry}"` };
    }
    return { value: normalized };
  });
}

const promptPulseBoardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom",
  placeholder: "alice, @bob, *",
  parseEntries: parsePulseBoardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseBoardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) =>
    (cfg as OpenClawConfig & { channels?: { pulseboard?: { dmPolicy?: string } } }).channels
      ?.pulseboard?.dmPolicy ?? "pairing",
  promptAllowFrom: promptPulseBoardAllowFrom,
});

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,

  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),

  validateInput: ({ input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      serverUrl?: string;
      apiToken?: string;
      handle?: string;
    };
    if (!typedInput.useEnv) {
      if (!typedInput.serverUrl?.trim()) {
        return "PulseBoard requires a server URL (--server-url) or --use-env.";
      }
      if (!typedInput.apiToken?.trim()) {
        return "PulseBoard requires an API token (--api-token) or --use-env.";
      }
      if (!typedInput.handle?.trim()) {
        return "PulseBoard requires a @handle (--handle) or --use-env.";
      }
    }
    return null;
  },

  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      serverUrl?: string;
      apiToken?: string;
      handle?: string;
    };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["serverUrl", "apiToken", "handle"] : undefined,
      patch: typedInput.useEnv
        ? {}
        : {
            serverUrl: typedInput.serverUrl?.trim(),
            apiToken: typedInput.apiToken?.trim(),
            handle: typedInput.handle?.trim().replace(/^@/, ""),
          },
    });
  },
};

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,

  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs server URL, API token, and handle",
    configuredHint: "configured",
    unconfiguredHint: "needs server URL, API token, and handle",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      resolvePulseBoardAccount({ cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"] })
        .configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseBoardAccount({
        cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
      });
      return account.configured
        ? [`Server: ${account.serverUrl}`, `Handle: @${account.handle}`]
        : [];
    },
  }),

  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },

  envShortcut: {
    prompt: "PULSEBOARD_API_TOKEN detected. Use env vars?",
    preferredEnvVar: "PULSEBOARD_API_TOKEN",
    isAvailable: ({ cfg, accountId }) => {
      if (accountId !== DEFAULT_ACCOUNT_ID) {
        return false;
      }
      const hasEnv = Boolean(
        process.env.PULSEBOARD_SERVER_URL?.trim() &&
          process.env.PULSEBOARD_API_TOKEN?.trim() &&
          process.env.PULSEBOARD_HANDLE?.trim(),
      );
      const account = resolvePulseBoardAccount({
        cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
        accountId,
      });
      return hasEnv && !hasConfiguredSecretInput(account.config.apiToken);
    },
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["serverUrl", "apiToken", "handle"],
        patch: {},
      }),
  },

  credentials: [
    {
      inputKey: "apiToken",
      providerHint: channel,
      credentialLabel: "API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      helpTitle: "PulseBoard API token",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inputPrompt: "PulseBoard API token",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
          accountId,
        });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiToken),
          resolvedValue: normalizeSecretInputString(account.config.apiToken),
          envValue: process.env.PULSEBOARD_API_TOKEN?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiToken"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiToken: resolvedValue },
        }),
    },
  ],

  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL (wss://...)",
      placeholder: "wss://boards.example.com",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard server URL",
      helpLines: ["Use a wss:// or ws:// WebSocket URL for the PulseBoard server."],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
          accountId,
        });
        return account.serverUrl;
      },
      keepPrompt: (value) => `Server URL set (${value}). Keep it?`,
      validate: ({ value }) => {
        const trimmed = value.trim();
        if (!trimmed) {
          return "Server URL is required.";
        }
        try {
          const parsed = new URL(trimmed);
          if (parsed.protocol !== "ws:" && parsed.protocol !== "wss:") {
            return "Server URL must use ws:// or wss:// protocol.";
          }
        } catch {
          return `Invalid URL: ${trimmed}`;
        }
        return undefined;
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { serverUrl: value.trim() },
        }),
    },
    {
      inputKey: "handle",
      message: "Your PulseBoard @handle",
      placeholder: "mybot",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard handle",
      helpLines: ["Your @handle on the PulseBoard server (without the leading @)."],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({
          cfg: cfg as Parameters<typeof resolvePulseBoardAccount>[0]["cfg"],
          accountId,
        });
        return account.handle;
      },
      keepPrompt: (value) => `Handle set (@${value}). Keep it?`,
      validate: ({ value }) => {
        const trimmed = value.trim().replace(/^@/, "");
        return trimmed ? undefined : "Handle is required.";
      },
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { handle: value.trim().replace(/^@/, "") },
        }),
    },
  ],

  dmPolicy: pulseBoardDmPolicy,

  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

