  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
  normalizePulseBoardTarget,
} from "./normalize.js";
import { getPulseBoardRuntime } from "./runtime.js";
import { sendMessagePulseBoard } from "./send.js";
import { pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import type { CoreConfig } from "./types.js";
import {
  collectStatusIssuesFromLastError,
  createDefaultChannelRuntimeState,
  createPreCryptoDirectDmAuthorizer,
  DEFAULT_ACCOUNT_ID,
  dispatchInboundDirectDmWithRuntime,
  dispatchInboundReplyWithBase,
  formatPairingApproveHint,
  GROUP_POLICY_BLOCKED_LABEL,
  readStoreAllowFromForDmPolicy,
  resolveAllowlistProviderRuntimeGroupPolicy,
  resolveDefaultGroupPolicy,
  resolveEffectiveAllowFromLists,
  resolveInboundDirectDmAccessWithRuntime,
  type ChannelPlugin,
} from "../runtime-api.js";

const CHANNEL_ID = "pulseboard" as const;

/** Normalize the raw allowFrom list to lowercase handles (or "*"). */
function normalizePulseBoardAllowlist(raw?: Array<string | number>): string[] {
