  for (const entry of allowFrom) {
    if (entry === "*") {
      return true;
    }
    if (entry.replace(/^@/, "") === normalized) {
      return true;
    }
  }
  return false;
}

// ── Config adapter ──────────────────────────────────────────────────────────

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: CHANNEL_ID,
  resolveAccount: (cfg) =>
    resolvePulseBoardAccount({ cfg: cfg as CoreConfig }),
  listAccountIds: (cfg) => listPulseBoardAccountIds(cfg as CoreConfig),
  defaultAccountId: (cfg) => resolveDefaultPulseBoardAccountId(cfg as CoreConfig),
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "serverUrl", "apiToken", "handle", "boards", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    formatNormalizedAllowFromEntries({
      allowFrom,
      normalizeEntry: normalizePulseBoardAllowEntry,
    }),
});

// ── DM security resolver ────────────────────────────────────────────────────

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: CHANNEL_ID,
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: formatPairingApproveHint(CHANNEL_ID),
  normalizeEntry: (raw) => normalizePulseBoardAllowEntry(raw) ?? raw,
});

// ── Inbound access resolver (DMs) ───────────────────────────────────────────

async function resolvePulseBoardDmAccess(params: {
  cfg: CoreConfig;
  accountId: string;
  dmPolicy: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom: Array<string | number> | undefined;
  senderHandle: string;
  rawBody: string;
  runtime: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["runtime"];
}) {
  return resolveInboundDirectDmAccessWithRuntime({
    cfg: params.cfg,
    channel: CHANNEL_ID,
    accountId: params.accountId,
    dmPolicy: params.dmPolicy,
    allowFrom: params.allowFrom,
    senderId: params.senderHandle,
    rawBody: params.rawBody,
    isSenderAllowed: isPulseBoardSenderAllowed,
    runtime: params.runtime,
    modeWhenAccessGroupsOff: "configured",
  });
}

// ── Resolve board config for a given board name ─────────────────────────────

function resolveBoardConfig(
  account: ResolvedPulseBoardAccount,
  boardName: string,
): {
  requireMention: boolean;
  allowFrom: string[];
  systemPrompt?: string;
} {
  const boardConfigs = account.config.boardConfigs ?? {};
  // Prefer exact match then wildcard "*".
  const cfg = boardConfigs[boardName] ?? boardConfigs["*"];
  return {
    requireMention: cfg?.requireMention !== false,
    allowFrom: normalizePulseBoardAllowlist(cfg?.allowFrom),
    systemPrompt: cfg?.systemPrompt?.trim() || undefined,
  };
}

// ── Main plugin ─────────────────────────────────────────────────────────────

// Track active client handles per account so the pairing notifier and
// outbound adapter can reuse them without reconnecting.
const activeClients = new Map<string, Awaited<ReturnType<typeof connectPulseBoardClient>>>();

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> = createChatChannelPlugin({
  base: {
    id: CHANNEL_ID,
    meta: {
      id: CHANNEL_ID,
      label: "PulseBoard",
      selectionLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board platform with named boards and direct messages.",
      order: 65,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    configSchema: pulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) =>
        describeAccountSnapshot({
          account,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            handle: account.handle,
          },
        }),
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardTargetId,
        hint: "<#board|@handle|handle>",
      },
    },
    status: {
      ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        collectStatusIssues: (accounts) =>
          collectStatusIssuesFromLastError(CHANNEL_ID, accounts),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            serverUrl:
              (snapshot as { serverUrl?: string }).serverUrl ?? null,
            handle: (snapshot as { handle?: string }).handle ?? null,
          }),
        resolveAccountSnapshot: ({ account, runtime }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            serverUrl: account.serverUrl,
            handle: account.handle,
            ...buildTrafficStatusSummary(runtime),
          },
        }),
      }),
    },
    gateway: {
      startAccount: async (ctx) => {
        const account = ctx.account;

        ctx.setStatus({
          accountId: account.accountId,
          serverUrl: account.serverUrl,
          handle: account.handle,
        });

        ctx.log?.info(
          `[${account.accountId}] starting PulseBoard provider ` +
            `(${account.serverUrl}, @${account.handle})`,
        );

        if (!account.configured) {
          throw new Error(
            `PulseBoard is not configured for account "${account.accountId}" ` +
              "(need serverUrl, apiToken, and handle in channels.pulseboard).",
          );
        }

        const runtime = getPulseBoardRuntime();

        const pairing = createChannelPairingController({
          core: runtime,
          channel: CHANNEL_ID,
          accountId: account.accountId,
        });

        // Pre-check DM access before processing message content.
        const resolveInboundAccess = async (senderHandle: string, rawBody: string) =>
          resolvePulseBoardDmAccess({
            cfg: ctx.cfg as CoreConfig,
            accountId: account.accountId,
            dmPolicy: account.config.dmPolicy ?? "pairing",
            allowFrom: account.config.allowFrom,
            senderHandle,
            rawBody,
            runtime: {
              shouldComputeCommandAuthorized:
                runtime.channel.commands.shouldComputeCommandAuthorized,
              resolveCommandAuthorizedFromAuthorizers:
                runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
            },
          });

        // Gate unknown DM senders before decoding message body.
        const authorizeDmSender = createPreCryptoDirectDmAuthorizer({
          resolveAccess: async (senderHandle) => resolveInboundAccess(senderHandle, ""),
          issuePairingChallenge: async ({ senderId, reply }) => {
            await pairing.issueChallenge({
              senderId,
              senderIdLine: `Your PulseBoard handle: @${senderId}`,
              sendPairingReply: reply,
              onCreated: () => {
                ctx.log?.debug?.(
                  `[${account.accountId}] pulseboard pairing request sender=@${senderId}`,
                );
              },
              onReplyError: (err) => {
                ctx.log?.warn?.(
                  `[${account.accountId}] pulseboard pairing reply failed for @${senderId}: ${String(err)}`,
                );
              },
            });
          },
          onBlocked: ({ senderId, reason }) => {
            ctx.log?.debug?.(
              `[${account.accountId}] blocked PulseBoard sender @${senderId} (${reason})`,
            );
          },
        });

        const client = await connectPulseBoardClient({
          serverUrl: account.serverUrl,
          apiToken: account.apiToken,
          handle: account.handle,
          boards: account.boards,
          abortSignal: ctx.abortSignal,

          onConnect: () => {
            ctx.log?.info(`[${account.accountId}] PulseBoard connected`);
          },

          onDisconnect: (reason) => {
            ctx.log?.info(`[${account.accountId}] PulseBoard disconnected: ${reason}`);
          },

          onError: (error) => {
            ctx.log?.error?.(
              `[${account.accountId}] PulseBoard error: ${error.message}`,
            );
          },

          onMessage: async (message) => {
            const rawBody = message.text.trim();
            if (!rawBody) {
              return;
            }

            if (!message.isGroup) {
              // ── Direct message ────────────────────────────────────────────

              // Gate before processing body content.
              const gateDecision = await authorizeDmSender({
                senderId: message.senderHandle,
                reply: async (text) => {
                  await client.sendDirect(message.senderHandle, text);
                },
              });
              if (gateDecision !== "allow") {
                return;
              }

              const resolvedAccess = await resolveInboundAccess(message.senderHandle, rawBody);
              if (resolvedAccess.access.decision !== "allow") {
                ctx.log?.warn?.(
                  `[${account.accountId}] dropping PulseBoard DM after preflight drift ` +
                    `(@${message.senderHandle}, ${resolvedAccess.access.reason})`,
                );
                return;
              }

              await dispatchInboundDirectDmWithRuntime({
                cfg: ctx.cfg,
                runtime,
                channel: CHANNEL_ID,
                channelLabel: "PulseBoard",
                accountId: account.accountId,
                peer: { kind: "direct", id: message.senderHandle },
                senderId: message.senderHandle,
                senderAddress: `pulseboard:@${message.senderHandle}`,
                recipientAddress: `pulseboard:@${account.handle}`,
                conversationLabel: `@${message.senderHandle}`,
                rawBody,
                messageId: message.messageId,
                timestamp: message.timestamp,
                commandAuthorized: resolvedAccess.commandAuthorized,
                deliver: async (payload) => {
                  const outboundText =
                    payload && typeof payload === "object" && "text" in payload
                      ? String((payload as { text?: string }).text ?? "")
                      : "";
                  if (!outboundText.trim()) {
                    return;
                  }
                  const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                    cfg: ctx.cfg,
                    channel: CHANNEL_ID,
                    accountId: account.accountId,
                  });
                  await client.sendDirect(
                    message.senderHandle,
                    runtime.channel.text.convertMarkdownTables(outboundText, tableMode),
                  );
                },
                onRecordError: (err) => {
                  ctx.log?.error?.(
                    `[${account.accountId}] failed recording PulseBoard DM session: ${String(err)}`,
                  );
                },
                onDispatchError: (err, info) => {
                  ctx.log?.error?.(
                    `[${account.accountId}] PulseBoard DM ${info.kind} reply failed: ${String(err)}`,
                  );
                },
              });
            } else {
              // ── Board (group) message ─────────────────────────────────────

              const defaultGroupPolicy = resolveDefaultGroupPolicy(ctx.cfg);
              const { groupPolicy } = resolveAllowlistProviderRuntimeGroupPolicy({
                providerConfigPresent: Boolean(
                  (ctx.cfg as CoreConfig).channels?.pulseboard,
                ),
                groupPolicy: account.config.groupPolicy,
                defaultGroupPolicy,
              });

              // Drop the board entirely if it is not in the allowlist (when policy is "allowlist").
              if (groupPolicy === "allowlist") {
                const subscribedBoards = account.boards.map((b) => b.toLowerCase());
                if (!subscribedBoards.includes(message.target.toLowerCase())) {
                  ctx.log?.debug?.(
                    `[${account.accountId}] pulseboard: drop board ${message.target} (not subscribed)`,
                  );
                  return;
                }
              }

              const boardCfg = resolveBoardConfig(account, message.target);
              const configGroupAllowFrom = normalizePulseBoardAllowlist(
                account.config.groupAllowFrom,
              );
              const boardAllowFrom =
                boardCfg.allowFrom.length > 0 ? boardCfg.allowFrom : configGroupAllowFrom;

              // Check sender allowlist for group messages.
              if (groupPolicy === "allowlist" && boardAllowFrom.length > 0) {
                if (!isPulseBoardSenderAllowed(message.senderHandle, boardAllowFrom)) {
                  ctx.log?.debug?.(
                    `[${account.accountId}] pulseboard: drop board sender @${message.senderHandle} ` +
                      `(not in groupAllowFrom for ${message.target})`,
                  );
                  return;
                }
              }

              // Check require-mention gate for board messages.
              if (boardCfg.requireMention) {
                const mentionPatterns = runtime.channel.mentions.buildMentionRegexes(ctx.cfg);
                const handlePattern = new RegExp(
                  `\\B@${account.handle.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`,
                  "i",
                );
                const wasMentioned =
                  runtime.channel.mentions.matchesMentionPatterns(rawBody, mentionPatterns) ||
                  handlePattern.test(rawBody);
                if (!wasMentioned) {
                  ctx.log?.debug?.(
                    `[${account.accountId}] pulseboard: skip board ${message.target} (no mention)`,
                  );
                  return;
                }
              }

              // Resolve group route.
              const peerId = message.target;
              const route = runtime.channel.routing.resolveAgentRoute({
                cfg: ctx.cfg,
                channel: CHANNEL_ID,
                accountId: account.accountId,
                peer: { kind: "group", id: peerId },
              });

              const storePath = runtime.channel.session.resolveStorePath(
                ctx.cfg.session?.store,
                { agentId: route.agentId },
              );
              const envelopeOptions = runtime.channel.reply.resolveEnvelopeFormatOptions(ctx.cfg);
              const previousTimestamp = runtime.channel.session.readSessionUpdatedAt({
                storePath,
                sessionKey: route.sessionKey,
              });
              const body = runtime.channel.reply.formatAgentEnvelope({
                channel: "PulseBoard",
                from: message.target,
                timestamp: message.timestamp,
                previousTimestamp,
                envelope: envelopeOptions,
                body: rawBody,
              });

              // Determine command authorization for board messages.
              const useAccessGroups = ctx.cfg.commands?.useAccessGroups !== false;
              const storeAllowFrom = await readStoreAllowFromForDmPolicy({
                provider: CHANNEL_ID,
                accountId: account.accountId,
                dmPolicy: "pairing",
                readStore: pairing.readStoreForDmPolicy,
              });
              const effectiveGroupAllowFrom = resolveEffectiveAllowFromLists({
                allowFrom: normalizePulseBoardAllowlist(account.config.allowFrom),
                groupAllowFrom: configGroupAllowFrom,
                storeAllowFrom: normalizePulseBoardAllowlist(storeAllowFrom),
                dmPolicy: account.config.dmPolicy ?? "pairing",
                groupAllowFromFallbackToAllowFrom: false,
              }).effectiveGroupAllowFrom;

              const senderAllowedForCommands = isPulseBoardSenderAllowed(
                message.senderHandle,
                effectiveGroupAllowFrom,
              );
              const commandAuthorized = runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers({
                useAccessGroups,
                authorizers: [
                  {
                    configured: effectiveGroupAllowFrom.length > 0,
                    allowed: senderAllowedForCommands,
                  },
                ],
                modeWhenAccessGroupsOff: "configured",
              });

              const ctxPayload = runtime.channel.reply.finalizeInboundContext({
                Body: body,
                RawBody: rawBody,
                CommandBody: rawBody,
                From: `pulseboard:board:${message.target}`,
                To: `pulseboard:board:${peerId}`,
                SessionKey: route.sessionKey,
                AccountId: route.accountId ?? account.accountId,
                ChatType: "group",
                ConversationLabel: message.target,
                SenderName: message.senderHandle,
                SenderId: `@${message.senderHandle}`,
                GroupSubject: message.target,
                GroupSystemPrompt: boardCfg.systemPrompt,
                Provider: CHANNEL_ID,
                Surface: CHANNEL_ID,
                MessageSid: message.messageId,
                MessageSidFull: message.messageId,
                Timestamp: message.timestamp,
                OriginatingChannel: CHANNEL_ID,
                OriginatingTo: `pulseboard:board:${peerId}`,
                CommandAuthorized: commandAuthorized,
              });

              await dispatchInboundReplyWithBase({
                cfg: ctx.cfg,
                channel: CHANNEL_ID,
                accountId: account.accountId,
                route,
                storePath,
                ctxPayload,
                core: runtime,
                deliver: async (payload) => {
                  const outboundText =
                    payload && typeof payload === "object" && "text" in payload
                      ? String((payload as { text?: string }).text ?? "")
                      : "";
                  if (!outboundText.trim()) {
                    return;
                  }
                  const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                    cfg: ctx.cfg,
                    channel: CHANNEL_ID,
                    accountId: account.accountId,
                  });
                  await client.postToBoard(
                    message.target,
                    runtime.channel.text.convertMarkdownTables(outboundText, tableMode),
                  );
                },
                onRecordError: (err) => {
                  ctx.log?.error?.(
                    `[${account.accountId}] failed recording PulseBoard board session: ${String(err)}`,
                  );
                },
                onDispatchError: (err, info) => {
                  ctx.log?.error?.(
                    `[${account.accountId}] PulseBoard board ${info.kind} reply failed: ${String(err)}`,
                  );
                },
              });
            }
          },
        });

        activeClients.set(account.accountId, client);

        ctx.log?.info(
          `[${account.accountId}] PulseBoard provider started, ` +
            `subscribed to ${account.boards.length} board(s)`,
        );

        return {
          stop: () => {
            client.disconnect();
            activeClients.delete(account.accountId);
            ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
          },
        };
      },
    },
  },

  pairing: {
    text: {
      idLabel: "pulseBoardHandle",
      message: "Your PulseBoard pairing request has been approved!",
      normalizeAllowEntry: (entry) => normalizePulseBoardAllowEntry(entry) ?? entry,
      notify: async ({ id, message }) => {
        const client = activeClients.get(DEFAULT_ACCOUNT_ID);
        if (client?.isConnected()) {
          // Strip any leading "@" so the handle is plain.
          await client.sendDirect(id.replace(/^@/, ""), message);
        }
      },
    },
  },

  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
  },

  outbound: {
    deliveryMode: "direct",
    // 4000-character chunk limit as specified for PulseBoard.
    textChunkLimit: 4000,
    sendText: async ({ cfg, to, text, accountId }) => {
      const core = getPulseBoardRuntime();
      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
      const client = activeClients.get(aid);
      const target = normalizePulseBoardTarget(to) ?? to;

      const tableMode = core.channel.text.resolveMarkdownTableMode({
        cfg,
        channel: CHANNEL_ID,
        accountId: aid,
      });
      const outboundText = core.channel.text.convertMarkdownTables(text ?? "", tableMode);

      if (client?.isConnected()) {
        if (isBoardTarget(target)) {
          await client.postToBoard(target, outboundText);
        } else {
          await client.sendDirect(target, outboundText);
        }
      } else {
        // Fall back to a transient send (e.g., for programmatic outbound).
        await sendMessagePulseBoard(to, text, { cfg: cfg as CoreConfig, accountId: aid });
      }

      return attachChannelToResult(CHANNEL_ID, {
        to: target,
        messageId: makePulseBoardMessageId(),
      });
    },
  },
});

/** Get the active PulseBoard client for an account, if running. */
export function getActivePulseBoardClient(
  accountId: string = DEFAULT_ACCOUNT_ID,
): Awaited<ReturnType<typeof connectPulseBoardClient>> | undefined {
  return activeClients.get(accountId);
}
